mapper.select:
merge into song_artist sa using ( values
(#{item.songId}::bigint, #{item.artistId}::bigint, #{item.roles}::jsonb)
) as s(song_id, artist_id, roles) on (sa.song_id = s.song_id and sa.artist_id = s.artist_id) when matched then update set roles = s.roles when not matched then insert (song_id, artist_id, roles) values (s.song_id, s.artist_id, s.roles) returning sa.song_id, sa.artist_id, sa.roles, merge_action() as action
